--
-- Name: parse_websearch(text); Type: FUNCTION; Schema: public; Owner: suite_clinica
--

CREATE FUNCTION public.parse_websearch(search_query text) RETURNS tsquery
    LANGUAGE sql IMMUTABLE
    AS $$
SELECT parse_websearch('pg_catalog.simple', search_query);
$$;


ALTER FUNCTION public.parse_websearch(search_query text) OWNER TO suite_clinica;

--
-- Name: parse_websearch(regconfig, text); Type: FUNCTION; Schema: public; Owner: suite_clinica
--

CREATE FUNCTION public.parse_websearch(config regconfig, search_query text) RETURNS tsquery
    LANGUAGE sql IMMUTABLE
    AS $$
SELECT
    string_agg(
        (
            CASE
                WHEN position('''' IN words.word) > 0 THEN CONCAT(words.word, ':*')
                ELSE words.word
            END
        ),
        ' '
    )::tsquery
FROM (
    SELECT trim(
        regexp_split_to_table(
            websearch_to_tsquery(config, lower(search_query))::text,
            ' '
        )
    ) AS word
) AS words
$$;


ALTER FUNCTION public.parse_websearch(config regconfig, search_query text) OWNER TO suite_clinica;

