    is_active boolean NOT NULL,
    expires_at timestamp without time zone,
    max_submissions integer,
    click_count integer,
    submission_count integer,
    last_clicked_at timestamp without time zone,
    custom_message text,
    custom_fields jsonb,
    created_at timestamp without time zone NOT NULL,
    updated_at timestamp without time zone NOT NULL,
    CONSTRAINT check_link_type_xor_v2 CHECK ((((user_id IS NOT NULL) AND (lead_id IS NULL) AND (check_number IS NULL)) OR ((user_id IS NULL) AND (lead_id IS NOT NULL) AND (check_number IS NOT NULL)))),
    CONSTRAINT check_number_valid CHECK (((check_number IS NULL) OR (check_number = ANY (ARRAY[1, 2, 3])))),
    CONSTRAINT sales_form_links_check CHECK (((expires_at IS NULL) OR (expires_at > created_at)))
);


